    parser.add_argument("--pattern", required=True, help="Regular expression to search for")
    return parser.parse_args()


def main() -> int:
    args = parse_args()
    root = Path(args.root)
    for path in find_matching_paths(root, args.pattern):
        print(path)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

